      expect(updated?.tags).toContain('work'); // normalized
    });

    it('should prevent duplicate tags', () => {
      const task = tracker.createTask('Tagged Task', 'Desc');
      tracker.addTag(task.id, 'IMPORTANT');
      tracker.addTag(task.id, 'important'); // duplicate

